code.C:
#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X1, X2; scanf("%lld %lld", &X1, &X2);
        if (X1 >= X2) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

